SELECT baseline.bldg_id, baseline.applicability, upgrade.applicability AS applicability_1 FROM (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade = 0) AS baseline JOIN (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade != 0) AS upgrade ON baseline.bldg_id = upgrade.bldg_id WHERE baseline.applicability = true AND upgrade.applicability = true AND upgrade.upgrade = 1 AND (baseline."out.electricity.total.energy_consumption" - upgrade."out.electricity.total.energy_consumption" >= 0.001 OR baseline."out.natural_gas.total.energy_consumption" - upgrade."out.natural_gas.total.energy_consumption" >= 0.001 OR baseline."out.fuel_oil.total.energy_consumption" - upgrade."out.fuel_oil.total.energy_consumption" >= 0.001 OR baseline."out.propane.total.energy_consumption" - upgrade."out.propane.total.energy_consumption" >= 0.001)